import React, { useState,useEffect } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";

function Recommendation(){

    /*const [carbs,setCarbs]=useState(0);
    const [calories,setCalories]=useState(0);*/
    const navigate=useNavigate();
    const [serverData,setServerData]=useState({
        BMI:0,
        total_carbs:0,
        total_calories:0,
        exerciseDuration:0,
        status:{
            BMIStatus:"",
            carbsStatus:"",
            calorieStatus:"",
            exerciseStatus:""
        },
        recommendations:[]
    });

    function goToDashboard(){
        navigate('/dashboard');
    }

    async function handlePage() {
        try{
            const response=await fetch('http://localhost:5000/recommendation');
            const data=await response.json();
            console.log(data);
            setServerData(data);
            /*setCalories(data[0].total_calories||0);
            setCarbs(data[0].total_carbs||0)*/
        }
        catch(err){
            console.log(err.message);
        }
    }
            
    useEffect(()=>{handlePage()},[]);

    return (
        <>
            <div>
                <h2>Your BMI is {serverData.BMI}</h2>
                <h2>Total Carbs consumed today is {serverData.total_carbs}</h2>
                <h2>Total Calories consumed today is {serverData.total_calories}</h2>
                <h2>Your total exercise duration is {serverData.exerciseDuration}</h2>
                <h3>BMI Status : {serverData.status?.BMIStatus}</h3>
                <h3>Carbs Status : {serverData.status?.carbsStatus}</h3>
                <h3>Calorie Status : {serverData.status?.calorieStatus}</h3>
                <h3>Exercise Status : {serverData.status?.exerciseStatus}</h3>
                {
                    serverData.recommendations?.map((item,index)=>
                        <p key={index}>{item}</p>
                    )
                }
                <button onClick={goToDashboard}>Go To Dashboard</button>
            </div>
        </>
    )
}

export default Recommendation;
